import * as t from "io-ts";
import { Optional, optionalNumber } from "../../../utils";
import { FeeUnit } from "./feeOptionUnit";
import { FeeFormula } from "./feeOptionFormula";
import { FeeType } from "./feeOptionFeeType";

export const FeeOption = t.partial({
  unit: Optional(FeeUnit),
  formula: Optional(FeeFormula),
  feeType: Optional(FeeType),
  gasLimit: optionalNumber,
  gasPrice: optionalNumber,
});

export type FeeOption = t.TypeOf<typeof FeeOption>;
